import React from 'react';
import './ResultCard.css';

const ECO_MESSAGES = {
  Recyclable:    'Recycling conserves raw materials and reduces energy use by up to 95%.',
  Biodegradable: 'Composting prevents methane emissions and returns nutrients to soil naturally.',
  Hazardous:     'Safe disposal protects water sources and prevents toxic soil contamination.',
};

export default function ResultCard({ category, impact, ecoPoints, bonusPoints }) {
  if (!category || !impact) return null;

  return (
    <div className="result-card">
      {/* Coloured top stripe */}
      <div className="result-stripe" style={{ background: impact.color }} />

      <div className="result-body">
        <div className="result-header">
          <div className="result-icon" style={{ background: impact.bg }}>
            {impact.icon}
          </div>
          <div>
            <p className="result-label">Classified As</p>
            <h2 className="result-category" style={{ color: impact.color }}>{category}</h2>
            {(impact.detectedObject || impact.confidence != null) && (
              <p className="metric-label" style={{ marginTop: 6 }}>
                {impact.detectedObject ? `Detected: ${impact.detectedObject}` : ''}
                {impact.detectedObject && impact.confidence != null ? ' · ' : ''}
                {impact.confidence != null ? `${Math.round(impact.confidence * 100)}% confidence` : ''}
              </p>
            )}
          </div>
        </div>

        <div className="result-bin" style={{ background: impact.bg }}>
          <span className="result-bin-label">Disposal Bin</span>
          <span className="result-bin-value" style={{ color: impact.color }}>{impact.bin}</span>
        </div>

        <div className="result-guidance">
          <p className="guidance-title">Disposal Guidance</p>
          <p className="guidance-text">{impact.guidance}</p>
        </div>
      </div>

      {ecoPoints > 0 && (
        <div className="eco-reward-banner">
          <div className="eco-reward-top">
            <span className="eco-reward-icon">🌱</span>
            <div>
              <p className="eco-reward-pts">+{ecoPoints + (bonusPoints || 0)} Eco-Points Earned</p>
              {bonusPoints > 0 && (
                <span className="eco-bonus-chip">+{bonusPoints} daily participation bonus included</span>
              )}
            </div>
          </div>
          <p className="eco-reward-msg">{ECO_MESSAGES[category] || ''}</p>
        </div>
      )}
    </div>
  );
}
